    if not isinstance(payload, dict):
        return False, "Payload must be a JSON object"

    if "event_type" not in payload and "type" not in payload:
        return False, "Missing required field: 'event_type' or 'type'"

    if partner == "stripe":
        required_fields = ["id", "type", "data"]
        for field in required_fields:
            if field not in payload:
                return False, f"Missing required Stripe field: '{field}'"

    elif partner == "paypal":
        required_fields = ["event_type", "resource"]
        for field in required_fields:
            if field not in payload:
                return False, f"Missing required PayPal field: '{field}'"

    elif partner == "square":
        required_fields = ["type", "data"]
        for field in required_fields:
            if field not in payload:
                return False, f"Missing required Square field: '{field}'"

    return True, "Valid"


