def normalize_event_type(partner: str, event_type: str) -> str:
    """Normalize event types across different payment partners."""
    event_mapping = {
        "stripe": {
            "payment_intent.succeeded": "payment.completed",
            "payment_intent.payment_failed": "payment.failed",
            "charge.refunded": "payment.refunded",
            "charge.dispute.created": "payment.disputed",
            "customer.subscription.created": "subscription.created",
            "customer.subscription.deleted": "subscription.cancelled",
            "invoice.paid": "invoice.paid",
            "invoice.payment_failed": "invoice.failed",
        },
        "paypal": {
            "PAYMENT.CAPTURE.COMPLETED": "payment.completed",
            "PAYMENT.CAPTURE.DENIED": "payment.failed",
            "PAYMENT.CAPTURE.REFUNDED": "payment.refunded",
            "CUSTOMER.DISPUTE.CREATED": "payment.disputed",
            "BILLING.SUBSCRIPTION.CREATED": "subscription.created",
            "BILLING.SUBSCRIPTION.CANCELLED": "subscription.cancelled",
        },
        "square": {
            "payment.completed": "payment.completed",
            "payment.failed": "payment.failed",
            "refund.created": "payment.refunded",
            "dispute.created": "payment.disputed",
            "subscription.created": "subscription.created",
            "subscription.stopped": "subscription.cancelled",
        }
    }

    partner_mapping = event_mapping.get(partner, {})
    return partner_mapping.get(event_type, f"unknown.{event_type}")


def create_response(status_code: int, message: str, data: dict = None) -> tuple:
    """Create a standardized JSON response."""
    response_body = {
        "status": "success" if status_code < 400 else "error",
        "message": message,
        "timestamp": datetime.now(timezone.utc).isoformat()
    }
    if data:
        response_body["data"] = data

    return (json.dumps(response_body), status_code, {"Content-Type": "application/json"})


