    """
    HTTP Cloud Function endpoint for processing payment webhook events.

    Deploy with:
        gcloud functions deploy payment-webhook \
            --gen2 \
            --runtime python312 \
            --trigger-http \
            --allow-unauthenticated \
            --entry-point payment_webhook \
            --set-env-vars WEBHOOK_SECRET=your-secret-here,ALLOWED_PARTNERS=stripe,paypal,square \
            --region us-central1 \
            --memory 256MB \
            --timeout 60s

    Partners call this endpoint with:
        POST /payment-webhook?partner=stripe
        Headers:
            Content-Type: application/json
            X-Webhook-Signature: sha256=<hmac_hex_digest>
            X-Webhook-Id: <unique_event_id>
        Body: JSON payload from payment provider
    """

    # --- Step 1: Method validation ---
    if request.method == "GET":
        # Health check endpoint
        return create_response(200, "Payment webhook endpoint is active")

